- Verification: ${ticket.verification_state}
- Approved plan: ${workflow.approved_plan ? "yes" : "no"}
- Needs reverification: ${ticketState.needs_reverification ? "yes" : "no"}

## Bootstrap

- status: ${workflow.bootstrap.status}
- last_verified_at: ${workflow.bootstrap.last_verified_at || "Not yet verified."}
- proof_artifact: ${workflow.bootstrap.proof_artifact || "None"}

## Process State

- process_version: ${workflow.process_version}
- pending_process_verification: ${workflow.pending_process_verification ? "true" : "false"}
- parallel_mode: ${workflow.parallel_mode}
- state_revision: ${workflow.state_revision}

## Lane Leases

${leases}

