export function renderStartHere(manifest: Manifest, workflow: WorkflowState, options: StartHereOptions = {}): string {
  const ticket = getTicket(manifest, workflow.active_ticket)
  const reopened = manifest.tickets.filter((item) => item.resolution_state === "reopened")
  const suspectDone = manifest.tickets.filter((item) => item.status === "done" && item.verification_state !== "trusted" && item.verification_state !== "reverified")
  const reverification = manifest.tickets.filter((item) => getTicketWorkflowState(workflow, item.id).needs_reverification)
  const blockedDependents = blockedDependentTickets(manifest, ticket.id)
  const verifierLabel = options.backlogVerifierAgent ? `\`${options.backlogVerifierAgent}\`` : "the backlog verifier"
  const recommendedAction = options.nextAction || (workflow.pending_process_verification ? `Use the team leader to route ${verifierLabel} across done tickets whose trust predates the current process contract.` : workflow.bootstrap.status !== "ready" ? "Run environment_bootstrap, register its proof artifact, then continue ticket execution." : blockedDependents.length > 0 && ticket.status !== "done" ? `Finish ${ticket.id} and its closeout proof before resuming dependent tickets: ${blockedDependents.map((item) => item.id).join(", ")}.` : "Continue the required internal lifecycle from the current ticket stage.")
  const summarizeTickets = (items: Ticket[]) => items.length > 0 ? items.map((item) => item.id).join(", ") : "none"
  const riskLines = [
    workflow.bootstrap.status !== "ready" ? "- Environment validation can fail for setup reasons until bootstrap proof exists." : null,
    workflow.pending_process_verification ? "- Historical completion should not be treated as fully trusted until pending process verification is cleared." : null,
    suspectDone.length > 0 ? "- Some done tickets are not fully trusted yet; use the backlog verifier before relying on earlier closeout." : null,
    blockedDependents.length > 0 && ticket.status !== "done" ? `- Downstream tickets ${blockedDependents.map((item) => item.id).join(", ")} remain formally blocked until ${ticket.id} reaches done.` : null,
  ].filter((line): line is string => Boolean(line)).join("
") || "- None recorded."
  return `# START HERE

${START_HERE_MANAGED_START}
## What This Repo Is

${manifest.project}

## Current State

The repo is operating under the managed OpenCode workflow. Use the canonical state files below instead of memory or raw ticket prose.

## Read In This Order

1. README.md
2. AGENTS.md
3. docs/spec/CANONICAL-BRIEF.md
4. docs/process/workflow.md
5. tickets/BOARD.md
6. tickets/manifest.json

## Current Or Next Ticket

- ID: ${ticket.id}
- Title: ${ticket.title}
- Wave: ${ticket.wave}
- Lane: ${ticket.lane}
- Stage: ${ticket.stage}
- Status: ${ticket.status}
- Resolution: ${ticket.resolution_state}
- Verification: ${ticket.verification_state}

## Dependency Status

- current_ticket_done: ${ticket.status === "done" ? "yes" : "no"}
- dependent_tickets_waiting_on_current: ${summarizeTickets(blockedDependents)}

## Generation Status

- handoff_status: ready for continued development
- process_version: ${workflow.process_version}
- parallel_mode: ${workflow.parallel_mode}
- pending_process_verification: ${workflow.pending_process_verification ? "true" : "false"}
- bootstrap_status: ${workflow.bootstrap.status}
- bootstrap_proof: ${workflow.bootstrap.proof_artifact || "None"}

## Post-Generation Audit Status

- audit_or_repair_follow_up: ${reopened.length > 0 || suspectDone.length > 0 || reverification.length > 0 ? "follow-up required" : "none recorded"}
- reopened_tickets: ${summarizeTickets(reopened)}
- done_but_not_fully_trusted: ${summarizeTickets(suspectDone)}
- pending_reverification: ${summarizeTickets(reverification)}

## Known Risks

${riskLines}

## Next Action

${recommendedAction}
${START_HERE_MANAGED_END}
`
}
function escapeRegExp(value: string): string { return value.replace(/[.*+?^${}()|[\]\]/g, "\$&") }
export function mergeStartHere(existing: string, rendered: string): string {
  const pattern = new RegExp(`${escapeRegExp(START_HERE_MANAGED_START)}[\s\S]*?${escapeRegExp(START_HERE_MANAGED_END)}`, "m")
  const renderedBlock = rendered.match(pattern)
  if (!renderedBlock) return rendered
  if (!existing.trim()) return rendered
  if (!existing.includes(START_HERE_MANAGED_START) || !existing.includes(START_HERE_MANAGED_END)) return existing
  return existing.replace(pattern, renderedBlock[0])
}

